INSERT INTO quiz_questions (day, question_no, source_doc, topic, question, choice_1, choice_2, choice_3, choice_4, answer, explanation) VALUES
(10, 1, '11', '캔들 패턴', '문서에서 도지(Doji) 캔들 패턴의 모양 특징으로 제시된 것은?', '짧은 몸통과 긴 아래 꼬리가 있으며 하락 후 나타난다', '몸통이 거의 없어 시가와 종가가 거의 같다', '큰 양봉이 앞날 음봉 전체를 덮는다', '세 개의 캔들 조합으로 음봉 → 도지 → 양봉 순으로 나타난다', 2, '문서 주요 캔들 패턴 표에서 도지(Doji)는 몸통이 거의 없음(시가≈종가)으로, 매수·매도 균형 및 방향 전환 가능성을 나타낸다고 설명합니다.'),
(10, 2, '11', '캔들 패턴', '문서에서 망치(Hammer) 캔들 패턴이 나타내는 신호는?', '강한 매도 전환 신호로 추세 반전이 임박했음을 나타낸다', '매수·매도 균형 상태로 방향 전환 가능성을 나타낸다', '매도세가 결국 매수세에 밀려 반등 신호임을 나타낸다', '상승 추세 마감 신호로 고점에서 나타난다', 3, '문서 주요 캔들 패턴 표에서 망치(Hammer)는 짧은 몸통과 긴 아래 꼬리를 가지며 하락 후 나타나 매도세가 결국 매수세에 밀리는 반등 신호라고 설명합니다.'),
(10, 3, '11', '캔들 패턴', '문서에서 교수형(Hanging Man) 패턴이 망치(Hammer)와 다른 점은?', '교수형은 긴 위 꼬리를 가지고 있어 반등 가능성을 나타낸다', '교수형은 상승 후 나타나 상승 추세 마감 신호를 나타낸다', '교수형은 세 캔들 조합으로 바닥 반전 강한 신호이다', '교수형은 몸통이 거의 없어 방향 전환 가능성을 나타낸다', 2, '문서 주요 캔들 패턴 표에서 교수형(Hanging Man)은 망치와 모양은 같지만 상승 후 나타나 상승 추세 마감 신호라고 설명합니다.'),
(10, 4, '11', '캔들 패턴', '문서에서 불리쉬 엔걸핑(Bullish Engulfing) 패턴의 모양 특징과 의미로 제시된 것은?', '큰 음봉이 앞날 양봉 전체를 덮어 강한 매도 전환 신호이다', '짧은 몸통과 긴 위 꼬리로 매수 시도 후 저항을 나타낸다', '큰 양봉이 앞날 음봉 전체를 덮어 강한 매수 전환 신호이다', '세 캔들이 음봉 → 도지 → 양봉 순으로 형성되어 바닥 반전 신호이다', 3, '문서 주요 캔들 패턴 표에서 불리쉬 엔걸핑(Bullish Engulfing)은 큰 양봉이 앞날 음봉 전체를 덮는 모양으로 강한 매수 전환 신호라고 설명합니다.'),
(10, 5, '11', '캔들 패턴', '문서에서 샛별(Morning Star) 패턴의 구성으로 제시된 것은?', '양봉 → 도지 → 음봉 3캔들 조합으로 고점 반전 신호이다', '음봉 → 도지 → 양봉 3캔들 조합으로 바닥 반전 강한 신호이다', '큰 양봉이 앞날 음봉 전체를 덮어 상승 전환 신호이다', '짧은 몸통과 긴 아래 꼬리를 가지며 반등 신호이다', 2, '문서 주요 캔들 패턴 표에서 샛별(Morning Star)은 음봉 → 도지 → 양봉의 3캔들 조합으로 바닥 반전 강한 신호라고 설명합니다.'),
(10, 6, '11', '캔들 패턴', '문서에서 캔들 패턴 실전 신뢰도 판단 흐름의 4조건 중 가장 마지막으로 확인하는 조건은?', '거래량이 평균보다 많은가?', '패턴 발생 위치가 지지선·저항선 근처인가?', '다음 봉이 방향을 확인해주는가?', '추세 방향과 일치하는가?', 4, '문서 실전 신뢰도 판단 흐름(flowchart)에서 지지·저항선 근처 → 거래량 초과 → 다음 봉 방향 확인 → 추세 방향 일치 순으로 확인하며, 4조건 모두 충족 시 높은 신뢰도 신호라고 설명합니다.'),
(10, 7, '11', '차트 패턴', '문서에서 헤드앤숄더(H&S) 패턴이 나타내는 신호로 제시된 것은?', '하락 추세 종료로 상승 전환 신호이다', '상승 추세 종료로 하락 전환 신호이다', '변동성 축소 후 기존 방향으로 돌파하는 지속 신호이다', '급등 후 잠시 쉬고 같은 방향 지속하는 패턴이다', 2, '문서 반전 패턴 표에서 헤드앤숄더(H&S)는 세 봉우리(중간이 가장 높음) 모양으로 상승 추세 종료, 하락 전환 신호라고 설명합니다.'),
(10, 8, '11', '차트 패턴', '문서에서 헤드앤숄더 패턴의 목표가 계산법으로 제시된 것은?', '목표가 = 넥라인 + (헤드 고점 - 넥라인)', '목표가 = 헤드 고점 - 넥라인', '목표가 = 넥라인 - (헤드 고점 - 넥라인)', '목표가 = 넥라인 × 0.618', 3, '문서 차트 패턴 실전 목표가 계산법 flowchart에서 헤드앤숄더 목표가(하락) = 넥라인 - (헤드 고점 - 넥라인)으로 계산한다고 설명합니다.'),
(10, 9, '11', '차트 패턴', '문서에서 이중바닥(Double Bottom) 패턴의 모양과 신호로 제시된 것은?', 'M자 모양으로 강한 저항 후 하락 전환 신호이다', '세 봉우리로 상승 추세 종료 후 하락 전환 신호이다', 'W자 모양으로 강한 지지 후 상승 전환 신호이다', '삼각형 수렴 후 기존 방향으로 돌파하는 지속 신호이다', 3, '문서 반전 패턴 표에서 이중바닥(Double Bottom)은 W자 모양(두 개의 비슷한 저점)으로 강한 지지 및 상승 전환 신호라고 설명합니다.'),
(10, 10, '11', '차트 패턴', '문서에서 삼각수렴(Triangle) 패턴의 의미로 제시된 것은?', '급등/급락 후 잠시 쉬고 같은 방향 지속하는 패턴이다', '변동성 축소 후 기존 방향으로 돌파하는 패턴이다', '깃발과 유사하나 삼각 수렴 형태인 지속 패턴이다', '세 봉우리 중 중간이 가장 높아 하락 전환을 나타낸다', 2, '문서 지속 패턴 표에서 삼각수렴(Triangle)은 변동성 축소 후 기존 방향으로 돌파하는 패턴이라고 설명합니다.'),
(10, 11, '11', '차트 패턴', '문서에서 이중바닥(Double Bottom) 목표가 계산법으로 제시된 것은?', '목표가 = 넥라인 - (천장 고점 - 넥라인)', '목표가 = 돌파점 + 삼각형 최대 높이', '목표가 = 넥라인 + (넥라인 - 바닥 저점)', '목표가 = 넥라인 × 1.618', 3, '문서 차트 패턴 실전 목표가 계산법 flowchart에서 이중바닥 목표가(상승) = 넥라인 + (넥라인 - 바닥 저점)으로 계산한다고 설명합니다.'),
(10, 12, '11', '차트 패턴', '문서에서 차트 패턴 신뢰도를 높이는 조건 중 "돌파 시 거래량 급증"의 효과로 제시된 것은?', '패턴 형성 시간이 길어져 이후 움직임이 커진다', '돌파의 진정성을 확인할 수 있다', '넥라인 돌파 후 재진입 기회를 제공한다', '여러 시간대에서 동시 형성되어 신호가 강해진다', 2, '문서 패턴 신뢰도 높이는 조건 표에서 돌파 시 거래량 급증의 효과는 돌파의 진정성 확인이라고 설명합니다.'),
(10, 13, '11', '엘리어트 파동', '문서에서 엘리어트 파동의 기본 구조로 제시된 것은?', '상승 7파 + 하락 3파의 10파 구조이다', '충격 5파 + 조정 3파의 8파 구조이다', '상승 3파 + 하락 2파의 5파 구조이다', '충격 8파 + 조정 5파의 13파 구조이다', 2, '문서에서 엘리어트 파동은 상승 추세에서 5개의 충격파(임펄스)와 3개의 조정파(a-b-c)가 한 사이클을 이루는 충격 5파 + 조정 3파의 8파 구조라고 설명합니다.'),
(10, 14, '11', '엘리어트 파동', '문서에서 엘리어트 파동 3파 진행 시 군중 심리로 제시된 것은?', '"소수만 인식, 반등 아닐까?"', '"역시 하락이었어" 공포 매도', '"진짜 상승이다!" 추세 추종', '"아직 올라!" 뒤늦은 매수', 3, '문서 파동 구분 및 군중 심리 표에서 3파는 강상승 파동으로 군중 심리는 "진짜 상승이다!" 추세 추종이라고 설명합니다.'),
(10, 15, '11', '엘리어트 파동', '문서에서 엘리어트 파동 절대 불변 규칙 중 2파에 관한 규칙은?', '2파는 3파보다 더 길면 카운팅이 무효이다', '2파는 1파의 시작점 이하로 내려가면 안 된다', '2파는 1파 고점의 50% 이하로 되돌리면 안 된다', '2파는 4파의 가격 영역과 겹치면 안 된다', 2, '문서 절대 불변 규칙 3가지 flowchart에서 규칙 1은 2파는 1파의 시작점 이하로 내려가면 안 되며, 이를 어기면 카운팅이 무효라고 설명합니다.'),
(10, 16, '11', '엘리어트 파동', '문서에서 엘리어트 파동 절대 불변 규칙 중 3파에 관한 규칙은?', '3파는 1파와 5파 중 하나보다 반드시 길어야 한다', '3파는 반드시 1파 크기의 1.618배 이상이어야 한다', '3파는 4파의 가격 영역과 겹치면 안 된다', '3파는 2파 저점 이하로 내려가면 카운팅이 무효이다', 1, '문서 절대 불변 규칙 3가지 flowchart에서 규칙 2는 3파는 5개 충격파 중 가장 짧은 파동이 되면 안 되며, 1파·5파 중 하나보다 반드시 길어야 한다고 설명합니다.'),
(10, 17, '11', '엘리어트 파동', '문서에서 엘리어트 파동 절대 불변 규칙 중 4파에 관한 규칙은?', '4파는 3파의 38.2% 이상 되돌리면 카운팅이 무효이다', '4파는 5파 시작점 이하로 내려가면 안 된다', '4파는 1파의 가격 영역과 겹치면 안 된다', '4파는 2파보다 반드시 짧아야 한다', 3, '문서 절대 불변 규칙 3가지 flowchart에서 규칙 3은 4파는 1파의 가격 영역과 겹치면 안 되며, 4파 저점이 1파 고점 아래로 내려가면 카운팅이 무효라고 설명합니다.'),
(10, 18, '11', '엘리어트 파동', '문서에서 엘리어트 3파의 일반적 피보나치 목표로 제시된 것은?', '0.382 × 1파 크기', '0.618 × 1파 크기', '1.618 × 1파 크기', '2.618 × 1파 크기', 3, '문서 파동별 피보나치 목표 표에서 3파는 1파 대비 연장으로 일반적 피보나치 목표가 1.618 × 1파 크기이며, 3파 목표가 = 1파 시작 + (1파 크기 × 1.618)이라고 설명합니다.'),
(10, 19, '11', '엘리어트 파동', '문서에서 엘리어트 4파의 일반적 피보나치 목표(되돌림 비율)로 제시된 것은?', '0.618 × 1파 크기 (61.8% 되돌림)', '0.500 × 3파 크기 (50.0% 되돌림)', '0.382 × 3파 크기 (38.2% 되돌림)', '0.236 × 3파 크기 (23.6% 되돌림)', 3, '문서 파동별 피보나치 목표 표에서 4파는 3파 되돌림으로 0.382 × 3파 크기(38.2% 되돌림)가 일반적 목표이며, 이는 얕은 조정을 나타낸다고 설명합니다.'),
(10, 20, '11', '엘리어트 파동', '문서에서 지그재그(Zigzag) 조정파의 구조로 제시된 것은?', '3-3-5 구조로 a파 저점 근처까지 하락하며 4파에서 자주 나타난다', '5-3-5 구조로 c파가 a파 저점 아래로 하락하며 2파에서 자주 나타난다', '3-3-3-3-3 구조로 수렴 후 돌파하며 b파에서 자주 나타난다', '5-5-5 구조로 강한 조정을 나타내며 매수 기회가 높다', 2, '문서 조정파동의 3가지 유형에서 지그재그(Zigzag)는 5-3-5 구조로 c파가 a파 저점 아래로 하락하며 2파에서 자주 나타나는 가장 흔한 조정 패턴이라고 설명합니다.'),
(10, 21, '11', '엘리어트 파동', '문서에서 플랫(Flat) 조정파가 주로 나타나는 파동 위치와 그 의미로 제시된 것은?', '2파에서 자주 나타나며 큰 조정으로 매수 기회가 낮다', 'b파에서 자주 나타나며 삼각형 수렴 후 돌파 방향이 추세이다', '4파에서 자주 나타나며 조정 폭이 얕아 강세장 신호이다', '5파 이후 나타나며 새로운 상승 추세의 시작을 나타낸다', 3, '문서 조정파동 유형 표에서 플랫(Flat)은 3-3-5 구조로 주로 4파에서 나타나며 조정 폭이 얕아 강세장 신호라고 설명합니다.'),
(10, 22, '11', '엘리어트 파동', '문서에서 엘리어트 파동 중 거래량이 폭발적으로 증가하며 가장 많은 거래량을 기록하는 파동은?', '1파 (소수가 먼저 매수하는 구간)', '2파 (공포 매도 후 소강 구간)', '3파 (추세 추종 + 뉴스 + 기관 매수 구간)', '5파 (뒤늦은 개인 매수 구간)', 3, '문서 거래량으로 파동 확인하기 표에서 3파는 폭발적 증가(가장 많음)하며 추세 추종, 뉴스, 기관 매수가 겹쳐 거래량이 집중된다고 설명합니다.'),
(10, 23, '11', '엘리어트 파동', '문서에서 2파 완성 후 3파 시작 예상 매수 시 손절 기준으로 제시된 것은?', '2파 저점 이탈 시', '3파 시작점 이탈 시', '1파 시작점 이탈 시', '피보나치 78.6% 되돌림 이탈 시', 3, '문서 파동별 실전 매매 전략 표에서 2파 완성 후 3파 시작 예상 매수의 손절 기준은 1파 시작점 이탈 시라고 설명합니다.'),
(10, 24, '11', '엘리어트 파동', '문서에서 엘리어트 파동의 프랙탈 구조(파동 속 파동)에서 설명하는 핵심 특성은?', '파동이 형성되는 시간대가 고정되어 있어 예측이 용이하다', '일봉에서 보이는 5파 구조 전체가 주봉으로 보면 단 하나의 파동일 수 있다', '작은 파동의 크기는 큰 파동 크기의 정확히 1/8이다', '같은 파동 번호는 항상 같은 크기를 유지한다', 2, '문서 파동의 프랙탈 구조 섹션에서 일봉에서 보이는 5파 구조 전체가 주봉으로 보면 단 하나의 3파일 수 있으며, 이 때문에 시간대를 여러 개 겹쳐 보는 것이 중요하다고 설명합니다.'),
(10, 25, '11', '엘리어트 파동', '문서에서 5파 말단 포지션 축소·매도 준비의 조건으로 제시된 것은?', 'RSI < 30 (과매도) + MACD 골든크로스 + 거래량 급증', 'RSI 다이버전스 + 거래량 감소 + 피보나치 확장 161.8% 도달', '피보나치 61.8% 지지 + 거래량 반등 + 정배열', '이전 저항선 돌파 + 거래량 회복 + MACD 골든크로스', 2, '문서 파동별 실전 매매 전략 표와 실전 조합 전략 섹션에서 5파 말단 매도 준비 조건은 RSI 다이버전스 + 거래량 감소 + 피보나치 확장 161.8% 도달이라고 설명합니다.'),
(10, 26, '11', '엘리어트 파동', '문서에서 실전 파동 식별 6단계 프로세스의 Step 3에서 검증하는 내용은?', '시간대 설정으로 주봉과 일봉을 동시에 분석한다', '명확한 고점·저점을 식별하여 전환점을 표시한다', '절대 규칙 3가지(2파·3파·4파 조건)를 검증한다', '피보나치 비율로 각 파동 크기가 부합하는지 확인한다', 3, '문서 실전 파동 식별 6단계 프로세스 flowchart에서 Step 3는 절대 규칙 3가지 검증으로 2파의 0% 이하 이탈 여부, 3파의 가장 짧은지 여부, 4파의 1파 고점 침범 여부를 확인한다고 설명합니다.'),
(10, 27, '11', '통합 리포트', '문서에서 통합 리포트에서 기술적 분석이 답하는 핵심 질문으로 제시된 것은?', '"이 기업이 싼가, 비싼가?"', '"기업의 내재가치는 얼마인가?"', '"지금이 사야 할 때인가?"', '"업종 평균 대비 ROE는 충분한가?"', 3, '문서 통합 리포트란 무엇인가 표에서 기술적 분석의 핵심 질문은 "지금이 사야 할 때인가?"라고 제시합니다.'),
(10, 28, '11', '통합 리포트', '문서에서 기본적 분석과 기술적 분석의 시간 지평 비교로 제시된 것은?', '기본적 분석은 단·중기(수일~수개월), 기술적 분석은 중·장기(6개월~수년)이다', '기본적 분석은 중·장기(6개월~수년), 기술적 분석은 단·중기(수일~수개월)이다', '기본적 분석과 기술적 분석 모두 중·장기(6개월~수년) 지평을 다룬다', '기본적 분석과 기술적 분석 모두 단기(수일~수주) 지평을 다룬다', 2, '문서 통합 리포트란 무엇인가 표에서 기본적 분석의 시간 지평은 중·장기(6개월~수년), 기술적 분석의 시간 지평은 단·중기(수일~수개월)라고 설명합니다.'),
(10, 29, '11', '통합 리포트', '문서에서 종목 스크리닝 1차 정량 필터의 부채비율 조건으로 제시된 것은?', '부채비율 ≤ 100%', '부채비율 ≤ 150%', '부채비율 ≤ 200%', '부채비율 ≤ 300%', 3, '문서 종목 선정 3단계 깔때기 flowchart에서 1차 스크리닝 정량 필터로 부채비율 ≤ 200%를 제시합니다.'),
(10, 30, '11', '통합 리포트', '문서에서 종목 스크리닝 3차 기술적 필터 조건 중 이동평균선 조건으로 제시된 것은?', 'MA5 > MA20 (단기 정배열)', 'MA20 > MA60 (정배열)', 'MA60 > MA200 (장기 정배열)', 'MA20 < MA60 (역배열 진입 구간)', 2, '문서 종목 선정 3단계 깔때기 flowchart에서 3차 스크리닝 기술적 필터 조건 중 하나로 MA20 > MA60(정배열)을 제시합니다.');
